const OpenAI = require('openai');

async function embed({ texts, model = 'text-embedding-3-small' }) {
  const openai = new OpenAI();
  const response = await openai.embeddings.create({ model, input: texts });
  return { vectors: response.data.map(d => d.embedding), dimensions: response.data[0].embedding.length, usage: response.usage };
}

module.exports = { embed };
